static void audit_log_event(uint32_t uid, uint8_t operation, uint8_t result,
			    const char *desc)
{
	k_mutex_lock(&audit_mutex, K_FOREVER);

	struct audit_entry *entry = &audit_log[audit_log_index % AUDIT_LOG_SIZE];
	entry->timestamp = k_uptime_get_32();
	entry->uid = uid;
	entry->operation = operation;
	entry->result = result;
	strncpy(entry->description, desc, sizeof(entry->description) - 1);
	entry->description[sizeof(entry->description) - 1] = '\0';
	audit_log_index++;

	printk("[AUDIT] ts=%u uid=%u op=%u result=%u: %s\n",
	       entry->timestamp, uid, operation, result, desc);

	k_mutex_unlock(&audit_mutex);
}

/*
 * Flash write operation - requires PRIV_WRITE
 */
static int flash_write(const struct task_identity *identity, uint32_t addr,
		       const uint8_t *data, uint32_t len)
{
	int ret;

	/* Privilege check */
	ret = check_privilege(identity, PRIV_WRITE);
	if (ret != 0) {
		audit_log_event(identity->uid, OP_FLASH_WRITE, REQ_DENIED,
				"Flash write denied - insufficient privileges");
		return ret;
	}

	/* Bounds check */
	if (addr + len > FLASH_SIM_SIZE) {
		printk("[FLASH] Write out of bounds: addr=%u len=%u max=%d\n",
		       addr, len, FLASH_SIM_SIZE);
		audit_log_event(identity->uid, OP_FLASH_WRITE, REQ_DENIED,
				"Flash write denied - out of bounds");
		return -EINVAL;
	}

	k_mutex_lock(&flash_mutex, K_FOREVER);

	/* Simulate flash erase before write (set to 0xFF) */
	memset(&flash_memory[addr], 0xFF, len);
	/* Write data */
	memcpy(&flash_memory[addr], data, len);

	k_mutex_unlock(&flash_mutex);

	printk("[FLASH] Write successful: addr=0x%04x len=%u by uid=%u\n",
	       addr, len, identity->uid);
	audit_log_event(identity->uid, OP_FLASH_WRITE, REQ_COMPLETED,
			"Flash write completed successfully");

	return 0;
}

/*
 * Flash read operation - requires PRIV_READ
 */
static int flash_read(const struct task_identity *identity, uint32_t addr,
		      uint8_t *data, uint32_t len)
{
	int ret;

	ret = check_privilege(identity, PRIV_READ);
	if (ret != 0) {
		audit_log_event(identity->uid, OP_STATUS_REQUEST, REQ_DENIED,
				"Flash read denied - insufficient privileges");
		return ret;
	}

	if (addr + len > FLASH_SIM_SIZE) {
		return -EINVAL;
	}

	k_mutex_lock(&flash_mutex, K_FOREVER);
	memcpy(data, &flash_memory[addr], len);
	k_mutex_unlock(&flash_mutex);

	printk("[FLASH] Read successful: addr=0x%04x len=%u by uid=%u\n",
	       addr, len, identity->uid);

	return 0;
}

/*
 * Configuration set - requires PRIV_WRITE
 */
static int config_set(const struct task_identity *identity, const char *key,
		      const char *value)
{
	int ret;

	ret = check_privilege(identity, PRIV_WRITE);
	if (ret != 0) {
		audit_log_event(identity->uid, OP_CONFIG_MODIFY, REQ_DENIED,
				"Config modify denied - insufficient privileges");
		return ret;
	}

	k_mutex_lock(&config_mutex, K_FOREVER);

	/* Look for existing key or empty slot */
	int target = -1;
	int empty_slot = -1;

	for (int i = 0; i < CONFIG_MAX_ENTRIES; i++) {
		if (system_config[i].in_use &&
		    strncmp(system_config[i].key, key, CONFIG_KEY_LEN) == 0) {
			/* Check per-entry write privilege */
			if ((identity->privilege_level & system_config[i].min_write_priv) !=
			    system_config[i].min_write_priv) {
				k_mutex_unlock(&config_mutex);
				audit_log_event(identity->uid, OP_CONFIG_MODIFY, REQ_DENIED,
						"Config entry write privilege insufficient");
				return -EACCES;
			}
			target = i;
			break;
		}
		if (!system_config[i].in_use && empty_slot < 0) {
			empty_slot = i;
		}
	}

	if (target < 0) {
		if (empty_slot < 0) {
			k_mutex_unlock(&config_mutex);
			printk("[CONFIG] No space for new entry\n");
			return -ENOMEM;
		}
		target = empty_slot;
	}

	strncpy(system_config[target].key, key, CONFIG_KEY_LEN - 1);
	system_config[target].key[CONFIG_KEY_LEN - 1] = '\0';
	strncpy(system_config[target].value, value, CONFIG_VAL_LEN - 1);
	system_config[target].value[CONFIG_VAL_LEN - 1] = '\0';
	system_config[target].in_use = true;
	/* New entries default to admin-only write */
	if (target == empty_slot) {
		system_config[target].min_read_priv = PRIV_READ;
		system_config[target].min_write_priv = PRIV_WRITE;
	}

	k_mutex_unlock(&config_mutex);

	printk("[CONFIG] Set '%s' = '%s' by uid=%u\n", key, value, identity->uid);
	audit_log_event(identity->uid, OP_CONFIG_MODIFY, REQ_COMPLETED,
			"Config modified successfully");

	return 0;
}

/*
 * Configuration get - requires PRIV_READ
 */
static int config_get(const struct task_identity *identity, const char *key,
		      char *value, size_t value_len)
{
	int ret;

	ret = check_privilege(identity, PRIV_READ);
	if (ret != 0) {
		audit_log_event(identity->uid, OP_CONFIG_READ, REQ_DENIED,
				"Config read denied - insufficient privileges");
		return ret;
	}

	k_mutex_lock(&config_mutex, K_FOREVER);

	for (int i = 0; i < CONFIG_MAX_ENTRIES; i++) {
		if (system_config[i].in_use &&
		    strncmp(system_config[i].key, key, CONFIG_KEY_LEN) == 0) {
			/* Check per-entry read privilege */
			if ((identity->privilege_level & system_config[i].min_read_priv) !=
			    system_config[i].min_read_priv) {
				k_mutex_unlock(&config_mutex);
				return -EACCES;
			}
			strncpy(value, system_config[i].value, value_len - 1);
			value[value_len - 1] = '\0';
			k_mutex_unlock(&config_mutex);
			printk("[CONFIG] Get '%s' = '%s' by uid=%u\n",
			       key, value, identity->uid);
			return 0;
		}
	}

	k_mutex_unlock(&config_mutex);
	return -ENOENT;
}

