/*
 * Admin task - processes privileged operation requests
 */
static void admin_task(void *p1, void *p2, void *p3)
{
	struct task_identity *identity = (struct task_identity *)p1;
	struct operation_request req;
	int ret;

	ARG_UNUSED(p2);
	ARG_UNUSED(p3);

	printk("\n[ADMIN] Admin task started (uid=%u, priv=0x%02x)\n",
	       identity->uid, identity->privilege_level);

	/* Initialize system */
	init_default_config();

	/* Perform initial admin operations */
	printk("\n[ADMIN] === Performing initial admin operations ===\n");

	/* Write firmware header to flash */
	const uint8_t fw_header[] = {0xDE, 0xAD, 0xBE, 0xEF, 0x01, 0x00, 0x00, 0x00};
	flash_write(identity, 0x00, fw_header, sizeof(fw_header));

	/* Write boot config to flash */
	const uint8_t boot_cfg[] = "BOOT=normal\0";
	flash_write(identity, 0x10, boot_cfg, sizeof(boot_cfg));

	/* Set some admin config */
	config_set(identity, "admin.last_login", "boot_time");
	config_set(identity, "sys.boot_count", "1");

	/* Signal that system is ready */
	k_sem_give(&system_ready_sem);

	printk("\n[ADMIN] === Entering request processing loop ===\n");

	/* Process incoming requests from user tasks */
	while (1) {
		ret = k_msgq_get(&request_queue, &req, K_MSEC(2000));

		if (ret == 0) {
			printk("\n[ADMIN] Processing request from uid=%u, op=%u\n",
			       req.requester_uid, req.operation);

			switch (req.operation) {
			case OP_FLASH_WRITE:
				printk("[ADMIN] Handling flash write request: "
				       "addr=0x%04x len=%u\n",
				       req.flash_addr, req.flash_data_len);

				/* Admin performs the write on behalf of user */
				ret = flash_write(identity, req.flash_addr,
						  req.flash_data,
						  req.flash_data_len);
				if (ret == 0) {
					req.status = REQ_COMPLETED;
					printk("[ADMIN] Flash write request "
					       "completed for uid=%u\n",
					       req.requester_uid);
				} else {
					req.status = REQ_DENIED;
					printk("[ADMIN] Flash write request "
					       "failed for uid=%u\n",
					       req.requester_uid);
				}
				break;

			case OP_CONFIG_MODIFY:
				printk("[ADMIN] Handling config modify request: "
				       "'%s' = '%s'\n", req.key, req.value);

				/* Validate the request - admin can reject */
				if (strncmp(req.key, "security.", 9) == 0) {
					printk("[ADMIN] Security config change "
					       "by uid=%u - extra validation\n",
					       req.requester_uid);
					/* Only allow if not changing to 'none' */
					if (strncmp(req.value, "none", 4) == 0) {
						req.status = REQ_DENIED;
						audit_log_event(
							req.requester_uid,
							OP_CONFIG_MODIFY,
							REQ_DENIED,
							"Security downgrade "
							"rejected by admin");
						printk("[ADMIN] REJECTED: "
						       "security downgrade "
						       "attempt by uid=%u\n",
						       req.requester_uid);
						break;
					}
				}

				ret = config_set(identity, req.key, req.value);
				req.status = (ret == 0) ? REQ_COMPLETED : REQ_DENIED;
				break;

			case OP_CONFIG_READ:
				printk("[ADMIN] Handling config read request: '%s'\n",
				       req.key);
				ret = config_get(identity, req.key,
						 req.value, CONFIG_VAL_LEN);
				req.status = (ret == 0) ? REQ_COMPLETED : REQ_DENIED;
				break;

			case OP_STATUS_REQUEST:
				printk("[ADMIN] Handling status request\n");
				snprintf(req.value, CONFIG_VAL_LEN,
					 "system=ok flash_free=%d configs=%d",
					 FLASH_SIM_SIZE, CONFIG_MAX_ENTRIES);
				req.status = REQ_COMPLETED;
				break;

			default:
				printk("[ADMIN] Unknown operation %u\n",
				       req.operation);
				req.status = REQ_DENIED;
				break;
			}

			/* Send response back to user */
			ret = k_msgq_put(&response_queue, &req, K_MSEC(1000));
			if (ret != 0) {
				printk("[ADMIN] Failed to send response\n");
			}
		} else {
			/* Periodic admin maintenance */
			printk("[ADMIN] Idle - performing maintenance check\n");

			/* Verify flash integrity (simple check) */
			uint8_t header[4];
			flash_read(identity, 0x00, header, 4);
			if (header[0] == 0xDE && header[1] == 0xAD &&
			    header[2] == 0xBE && header[3] == 0xEF) {
				printk("[ADMIN] Flash integrity check: OK\n");
			} else {
				printk("[ADMIN] Flash integrity check: "
				       "WARNING - header corrupted\n");
			}
		}
	}
}

/*
 * Helper: user submits a request and waits for response
 */
static int user_submit_request(struct operation_request *req, int timeout_ms)
{
	int ret;

	req->status = REQ_PENDING;

	ret = k_msgq_put(&request_queue, req, K_MSEC(timeout_ms));
	if (ret != 0) {
		printk("[USER] Failed to submit request (queue full)\n");
		return -EAGAIN;
	}

	printk("[USER] Request submitted, waiting for response...\n");

	ret = k_msgq_get(&response_queue, req, K_MSEC(timeout_ms * 2));
	if (ret != 0) {
		printk("[USER] Timeout waiting for response\n");
		return -ETIMEDOUT;
	}

	return (req->status == REQ_COMPLETED) ? 0 : -EACCES;
}

/*
 * User task - demonstrates permission-limited operations and
 * privilege escalation through the request system
 */
static void user_task(void *p1, void *p2, void *p3)
{
	struct task_identity *identity = (struct task_identity *)p1;
	struct operation_request req;
	int ret;
	char value_buf[CONFIG_VAL_LEN];

	ARG_UNUSED(p2);
	ARG_UNUSED(p3);

	/* Wait for system to be initialized by admin */
	k_sem_take(&system_ready_sem, K_FOREVER);

	printk("\n[USER] User task started (uid=%u, priv=0x%02x)\n",
	       identity->uid, identity->privilege_level);

	/* === Demonstrate direct operations with user privileges === */
	printk("\n[USER] === Testing direct operations with user privileges ===\n");

	/* User can read config directly (has READ privilege) */
	ret = config_get(identity, "sys.hostname", value_buf, sizeof(value_buf));
	if (ret == 0) {
		printk("[USER] Direct config read SUCCESS: hostname='%s'\n",
		       value_buf);
	} else {
		printk("[USER] Direct config read FAILED\n");
	}

	ret = config_get(identity, "sys.version", value_buf, sizeof(value_buf));
	if (ret == 0) {
		printk("[USER] Direct config read SUCCESS: version='%s'\n",
		       value_buf);
	}

	/* User CANNOT write config directly (no WRITE privilege) */
	printk("\n[USER] Attempting direct config write (should fail)...\n");
	ret = config_set(identity, "sys.hostname", "hacked-device");
	if (ret == -EACCES) {
		printk("[USER] Direct config write DENIED as expected!\n");
	}

	/* User CANNOT write flash directly */
	printk("\n[USER] Attempting direct flash write (should fail)...\n");
	uint8_t test_data[] = {0x41, 0x42, 0x43};
	ret = flash_write(identity, 0x80, test_data, sizeof(test_data));
	if (ret == -EACCES) {
		printk("[USER] Direct flash write DENIED as expected!\n");
	}

	/* User CAN read flash (has READ privilege) */
	uint8_t read_buf[8];
	ret = flash_read(identity, 0x00, read_buf, sizeof(read_buf));
	if (ret == 0) {
		printk("[USER] Direct flash read SUCCESS: "
		       "%02x %02x %02x %02x %02x %02x %02x %02x\n",
		       read_buf[0], read_buf[1], read_buf[2], read_buf[3],
		       read_buf[4], read_buf[5], read_buf[6], read_buf[7]);
	}

	k_sleep(K_MSEC(500));

	/* === Demonstrate privilege escalation through request system === */
	printk("\n[USER] === Requesting admin operations through privilege system ===\n");

	/* Request 1: Ask admin to write to flash */
	printk("\n[USER] Requesting flash write through admin...\n");
	memset(&req, 0, sizeof(req));
	req.requester_uid = identity->uid;
	req.operation = OP_FLASH_WRITE;
	req.flash_addr = 0x80;
	memcpy(req.flash_data, "UserData", 8);
	req.flash_data_len = 8;

	ret = user_submit_request(&req, 5000);
	if (ret == 0) {
		printk("[USER] Flash write via admin: SUCCESS\n");

		/* Verify the write by reading directly */
		uint8_t verify[8];
		flash_read(identity, 0x80, verify, 8);
		printk("[USER] Verification read: '%c%c%c%c%c%c%c%c'\n",
		       verify[0], verify[1], verify[2], verify[3],
		       verify[4], verify[5], verify[6], verify[7]);
	} else {
		printk("[USER] Flash write via admin: FAILED (%d)\n", ret);
	}

	k_sleep(K_MSEC(500));

	/* Request 2: Ask admin to modify config */
	printk("\n[USER] Requesting config change through admin...\n");
	memset(&req, 0, sizeof(req));
	req.requester_uid = identity->uid;
	req.operation = OP_CONFIG_MODIFY;
	strncpy(req.key, "net.ip_addr", CONFIG_KEY_LEN - 1);
	strncpy(req.value, "10.0.0.50", CONFIG_VAL_LEN - 1);

	ret = user_submit_request(&req, 5000);
	if (ret == 0) {
		printk("[USER] Config change via admin: SUCCESS\n");

		/* Verify by reading */
		config_get(identity, "net.ip_addr", value_buf, sizeof(value_buf));
		printk("[USER] Verified new IP: '%s'\n", value_buf);
	} else {
		printk("[USER] Config change via admin: FAILED (%d)\n", ret);
	}

	k_sleep(K_MSEC(500));

	/* Request 3: Try to downgrade security (should be rejected by admin) */
	printk("\n[USER] Attempting security downgrade through admin "
	       "(should be rejected)...\n");
	memset(&req, 0, sizeof(req));
	req.requester_uid = identity->uid;
	req.operation = OP_CONFIG_MODIFY;
	strncpy(req.key, "security.level", CONFIG_KEY_LEN - 1);
	strncpy(req.value, "none", CONFIG_VAL_LEN - 1);

	ret = user_submit_request(&req, 5000);
	if (ret == -EACCES) {
		printk("[USER] Security downgrade REJECTED by admin as expected!\n");
	} else if (ret == 0) {
		printk("[USER] Security downgrade unexpectedly approved!\n");
	}

	k_sleep(K_MSEC(500));

	/* Request 4: Legitimate security config change */
	printk("\n[USER] Requesting legitimate security config change...\n");
	memset(&req, 0, sizeof(req));
	req.requester_uid = identity->uid;
	req.operation = OP_CONFIG_MODIFY;
	strncpy(req.key, "security.level", CONFIG_KEY_LEN - 1);
	strncpy(req.value, "maximum", CONFIG_VAL_LEN - 1);

	ret = user_submit_request(&req, 5000);
	if (ret == 0) {
		printk("[USER] Security upgrade: SUCCESS\n");
		config_get(identity, "security.level", value_buf, sizeof(value_buf));
		printk("[USER] New security level: '%s'\n", value_buf);
	}

	k_sleep(K_MSEC(500));

	/* Request 5: Get system status */
	printk("\n[USER] Requesting system status...\n");
	memset(&req, 0, sizeof(req));
	req.requester_uid = identity->uid;
	req.operation = OP_STATUS_REQUEST;

	ret = user_submit_request(&req, 5000);
	if (ret == 0) {
		printk("[USER] System status: '%s'\n", req.value);
	}

	k_sleep(K_MSEC(500));

	/* Request 6: Write application data to flash */
	printk("\n[USER] Requesting application data flash write...\n");
	memset(&req, 0, sizeof(req));
	req.requester_uid = identity->uid;
	req.operation = OP_FLASH_WRITE;
	req.flash_addr = 0xA0;
	const char *app_data = "APP_CFG:v2.1";
	memcpy(req.flash_data, app_data, strlen(app_data));
	req.flash_data_len = strlen(app_data);

	ret = user_submit_request(&req, 5000);
	if (ret == 0) {
		printk("[USER] Application data write: SUCCESS\n");
	}

	/* Final summary */
	printk("\n[USER] === User task operations complete ===\n");
	printk("[USER] Summary:\n");
	printk("[USER]   - Direct reads: ALLOWED (user has READ privilege)\n");
	printk("[USER]   - Direct writes: DENIED (user lacks WRITE privilege)\n");
	printk("[USER]   - Admin-mediated writes: ALLOWED (through request system)\n");
	printk("[USER]   - Security downgrades: REJECTED (admin policy enforcement)\n");

	/* User task continues running, periodically reading config */
	while (1) {
		k_sleep(K_MSEC(5000));
		printk("\n[USER] Periodic status check...\n");
		config_get(identity, "sys.hostname", value_buf, sizeof(value_buf));
		printk("[USER] hostname='%s'\n", value_buf);
	}
}

/*
 * Main entry point
 */
int main(void)
{
	printk("===========================================\n");
	printk("  Zephyr RTOS Privilege System Demo\n");
	printk("  Embedded Linux-like Permission Model\n");
	printk("===========================================\n\n");

	/* Initialize mutexes */
	k_mutex_init(&flash_mutex);
	k_mutex_init(&config_mutex);
	k_mutex_init(&audit_mutex);

	printk("[MAIN] Privilege levels:\n");
	printk("[MAIN]   PRIV_NONE    = 0x%02x\n", PRIV_NONE);
	printk("[MAIN]   PRIV_READ    = 0x%02x\n", PRIV_READ);
	printk("[MAIN]   PRIV_WRITE   = 0x%02x\n", PRIV_WRITE);
	printk("[MAIN]   PRIV_EXECUTE = 0x%02x\n", PRIV_EXECUTE);
	printk("[MAIN]   PRIV_ADMIN   = 0x%02x\n", PRIV_ADMIN);
	printk("[MAIN]   PRIV_USER    = 0x%02x\n\n", PRIV_USER);

	/* Create admin task (higher priority) */
	admin_identity.tid = k_thread_create(
		&admin_thread_data, admin_stack,
		K_THREAD_STACK_SIZEOF(admin_stack),
		admin_task, &admin_identity, NULL, NULL,
		ADMIN_PRIORITY, 0, K_NO_WAIT);
	k_thread_name_set(admin_identity.tid, "admin_task");

	/* Create user task (lower priority) */
	user_identity.tid = k_thread_create(
		&user_thread_data, user_stack,
		K_THREAD_STACK_SIZEOF(user_stack),
		user_task, &user_identity, NULL, NULL,
		USER_PRIORITY, 0, K_NO_WAIT);
	k_thread_name_set(user_identity.tid, "user_task");

	printk("[MAIN] Tasks created. Admin (prio=%d), User (prio=%d)\n",
	       ADMIN_PRIORITY, USER_PRIORITY);
	printk("[MAIN] System running...\n\n");

	return 0;
}